import React, { useState, useEffect, useCallback } from "react";
import "./LiveBlocks.css";

const LiveBlocks = ({ parameters }) => {
  const [data, setData] = useState({});

  const fetchParameters = useCallback(async function() {
    try {
      // Cache busting for older browsers on Raspberry Pi
      var timestamp = new Date().getTime();
      var response = await fetch('/parameters.json?t=' + timestamp);

      if (!response.ok) return;

      var jsonArray = await response.json();
      var formattedData = {};

      // Using standard forEach for better compatibility
      jsonArray.forEach(function(item) {
        if (item.key) {
          formattedData[item.key] = item.value;
        }
      });

      setData(formattedData);
    } catch (e) {
      console.error("CONSOLE: Fetch error", e);
    }
  }, []);

  useEffect(function() {
    fetchParameters();
    var id = setInterval(fetchParameters, 200);
    return function() { clearInterval(id); };
  }, [fetchParameters]);

  return (
    <div className="live-blocks-container">
      {parameters.map(function(param) {
        // Fallback logic for values to avoid modern Nullish Coalescing (??)
        var val = data[param.key];
        var displayValue = (val !== undefined && val !== null) ? val : "---";

        return (
          /* FIX: Added the unique 'key' prop here to stop the React warning */
          <div key={param.key} className="live-block">
            <div className="block-label">{param.label}</div>
            <div className="block-value">
              {displayValue}
              <span className="block-unit">{param.unit || ""}</span>
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default LiveBlocks;
